// Skip PDF fetch: pass articles through without downloading
const articles = $('Input').all().map(i => i.json);
console.log('PDF Fetch SKIPPED: ' + articles.length + ' articles passed through without PDF download');
return articles.map(a => ({ json: { ...a, pdf_url: null, pdf_local: null, pdf_source: null, is_oa: false, oa_status: 'pdf_fetch_skipped' } }));

// === PDF FETCH v2 - Telechargement reel des PDFs ===
// Sources: 1) Unpaywall (OA legal) 2) CORE.ac.uk (fallback OA)
// Telecharge les fichiers via le proxy /download

const PROXY = 'http://host.docker.internal:3456';
const EMAIL = 'ultralab-review@systematic-review.org';
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { error: 'no_input' } }];
}

const allArticles = items.map(i => i.json);
const outputFolder = (allArticles[0] && allArticles[0].output_folder) || 'C:\\Users\\Mika\\Desktop\\review ultralab';
const pdfFolder = outputFolder + '\\pdfs';

const toFetch = allArticles.filter(a => a.screening_decision === 'Include' || a.screening_decision === 'Maybe');
const excluded = allArticles.filter(a => a.screening_decision === 'Exclude');

console.log('PDF Fetch v2: ' + toFetch.length + ' articles a traiter, ' + excluded.length + ' exclus');
console.log('Dossier PDFs: ' + pdfFolder);

let stats = { unpaywall: 0, core: 0, downloaded: 0, failed: 0, no_doi: 0 };
const results = []; /* PROGRESS_PDF_START_v1 */ try { await this.helpers.httpRequest({ method:'POST', url:'http://host.docker.internal:8080/api/module-progress/start', body:JSON.stringify({mode:'pdf-fetch', total:toFetch.length, label:'pdf-fetch'}), headers:{'Content-Type':'application/json'}, timeout:3000 }); } catch(e) {}

function sanitizeFilename(name) {
  return (name || 'article').substring(0, 80).replace(/[^a-zA-Z0-9_-]/g, '_').replace(/_+/g, '_');
}

for (let i = 0; i < toFetch.length; i++) {
  const article = { ...toFetch[i] };
  if (i % 3 === 0) { try { await this.helpers.httpRequest({ method:'POST', url:'http://host.docker.internal:8080/api/module-progress/tick', body:JSON.stringify({current:i, total:toFetch.length}), headers:{'Content-Type':'application/json'}, timeout:2000 }); } catch(e) {} } /* PROGRESS_PDF_TICK_v1 */
  const doi = (article.doi || '').trim();
  let pdf_url = null;
  let pdf_source = null;
  let pdf_local = null;

  if (!doi) {
    stats.no_doi++;
    if (i < 5) console.log('  [' + (i+1) + '] Pas de DOI - ' + (article.title || '').substring(0, 50));
    results.push({ ...article, pdf_url: null, pdf_local: null, is_oa: false, oa_status: 'no_doi', pdf_source: null });
    continue;
  }


  // === ZOTERO_PDF_SOURCE_v1 - SOURCE 0 : biblio user Zotero (prioritaire) ===
  if (doi) {
    try {
      const dockerPdfFolder = (outputFolder || '').replace(/\\/g, '/').replace(/^[A-Z]:\/Users\/[^/]+\/Desktop/i, '/desktop') + '/pdfs';
      const zotResp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://host.docker.internal:8080/api/zotero/find-pdf',
        body: JSON.stringify({
          doi: doi,
          dest_folder: dockerPdfFolder,
          filename_hint: sanitizeFilename(article.title || doi)
        }),
        headers: { 'Content-Type': 'application/json' },
        json: true,
        timeout: 120000
      });
      if (zotResp && zotResp.found && zotResp.downloaded) {
        pdf_url = 'zotero://local';
        pdf_source = 'zotero';
        pdf_local = zotResp.path_docker || zotResp.path;
        stats.zotero = (stats.zotero || 0) + 1;
        stats.downloaded++;
        article._zotero_item_key = zotResp.item_key || null;
        article.is_oa = true;
        article.oa_status = 'zotero_local';
        results.push({ ...article, pdf_url, pdf_local, pdf_source });
        if (i < toFetch.length - 1) {
          await new Promise(resolve => setTimeout(resolve, 200));
        }
        continue;
      }
    } catch (e) {
      // Zotero indisponible, on continue silencieusement vers Unpaywall
    }
  }

  // === SOURCE 1: Unpaywall (OA legal, gratuit) ===
  try {
    const targetUrl = 'https://api.unpaywall.org/v2/' + encodeURIComponent(doi) + '?email=' + EMAIL;
    const proxyUrl = PROXY + '?url=' + encodeURIComponent(targetUrl);
    const uw = await this.helpers.httpRequest({ method: 'GET', url: proxyUrl, timeout: 20000 });

    if (uw && uw.best_oa_location) {
      pdf_url = uw.best_oa_location.url_for_pdf || null;
    }
    if (!pdf_url && uw && Array.isArray(uw.oa_locations)) {
      for (const loc of uw.oa_locations) {
        if (loc.url_for_pdf) { pdf_url = loc.url_for_pdf; break; }
      }
    }
    if (pdf_url) {
      pdf_source = 'unpaywall';
      stats.unpaywall++;
    }
    article.is_oa = (uw && uw.is_oa) || false;
    article.oa_status = (uw && uw.oa_status) || 'unknown';
  } catch(e) {
    article.is_oa = false;
    article.oa_status = 'unpaywall_error';
  }

  // === SOURCE 2: CORE.ac.uk (fallback OA, gratuit sans cle) ===
  if (!pdf_url && doi) {
    try {
      const coreUrl = 'https://api.core.ac.uk/v3/search/works?q=doi:' + encodeURIComponent(doi) + '&limit=1';
      const coreProxyUrl = PROXY + '?url=' + encodeURIComponent(coreUrl);
      const coreResp = await this.helpers.httpRequest({ method: 'GET', url: coreProxyUrl, timeout: 15000 });

      if (coreResp && Array.isArray(coreResp.results) && coreResp.results.length > 0) {
        const work = coreResp.results[0];
        if (work.downloadUrl) {
          pdf_url = work.downloadUrl;
          pdf_source = 'core';
          stats.core++;
        } else if (work.sourceFulltextUrls && work.sourceFulltextUrls.length > 0) {
          pdf_url = work.sourceFulltextUrls[0];
          pdf_source = 'core';
          stats.core++;
        }
      }
    } catch(e) {
      // CORE indisponible, on continue
    }
  }

  // === SOURCE 3: Europe PMC (gratuit, large couverture biomed) ===
  if (!pdf_url && doi) {
    try {
      const epmcUrl = 'https://www.ebi.ac.uk/europepmc/webservices/rest/search?query=DOI:' + encodeURIComponent(doi) + '&resultType=core&format=json';
      const epmcProxyUrl = PROXY + '?url=' + encodeURIComponent(epmcUrl);
      const epmcResp = await this.helpers.httpRequest({ method: 'GET', url: epmcProxyUrl, timeout: 15000 });
      const result = epmcResp && epmcResp.resultList && epmcResp.resultList.result && epmcResp.resultList.result[0];
      if (result) {
        // Europe PMC fournit des fullTextUrlList avec type=Article + documentStyle=pdf
        const urls = (result.fullTextUrlList && result.fullTextUrlList.fullTextUrl) || [];
        for (const u of urls) {
          if (u.documentStyle === 'pdf' && (u.availability === 'Open access' || u.availability === 'Free')) {
            pdf_url = u.url; pdf_source = 'europepmc'; stats.europepmc = (stats.europepmc||0)+1; break;
          }
        }
        // Fallback : PMCID -> URL directe PDF
        if (!pdf_url && result.pmcid) {
          pdf_url = 'https://europepmc.org/articles/' + result.pmcid + '?pdf=render';
          pdf_source = 'europepmc'; stats.europepmc = (stats.europepmc||0)+1;
        }
      }
    } catch(e) { /* EPMC indispo */ }
  }

  // === TELECHARGEMENT REEL DU PDF ===
  if (pdf_url) {
    try {
      const filename = sanitizeFilename(article.title) + '.pdf';
      const savePath = pdfFolder + '\\' + filename;

      const dlResp = await this.helpers.httpRequest({
        method: 'POST',
        url: PROXY + '/download',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url: pdf_url, save_to: savePath }),
        timeout: 60000
      });

      if (dlResp && dlResp.success) {
        pdf_local = savePath;
        stats.downloaded++;
        if (i < 10) console.log('  [' + (i+1) + '] PDF OK (' + pdf_source + ') - ' + filename.substring(0, 40));
      } else {
        stats.failed++;
        if (i < 10) console.log('  [' + (i+1) + '] Echec DL - ' + (dlResp && dlResp.error || 'unknown'));
      }
    } catch(e) {
      stats.failed++;
      if (i < 5) console.log('  [' + (i+1) + '] Erreur download: ' + e.message.substring(0, 60));
    }
  } else {
    article.url = article.url || ('https://doi.org/' + doi);
  }

  results.push({ ...article, pdf_url, pdf_local, pdf_source });

  // Rate limiting (200ms entre chaque requete)
  if (i < toFetch.length - 1) {
    await new Promise(resolve => setTimeout(resolve, 200));
  }
}

// Ajouter les exclus sans modification
const excludedResults = excluded.map(a => ({
  ...a, pdf_url: null, pdf_local: null, pdf_source: null, is_oa: false, oa_status: 'excluded_from_fetch'
}));

const allResults = [...results, ...excludedResults];

const noOaUrl = toFetch.length - stats.no_doi - stats.unpaywall - (stats.core||0) - (stats.europepmc||0);
console.log('=== PDF FETCH v3 SUMMARY ===');
console.log('Articles trouves dans Zotero (biblio user) : ' + (stats.zotero || 0));
console.log('Articles a traiter      : ' + toFetch.length);
console.log('  Sans DOI (skip)       : ' + stats.no_doi);
console.log('  URL OA trouvee :');
console.log('    Unpaywall            : ' + stats.unpaywall);
console.log('    CORE.ac.uk           : ' + (stats.core||0));
console.log('    Europe PMC           : ' + (stats.europepmc||0));
console.log('  Aucune URL OA trouvee : ' + Math.max(0, noOaUrl) + ' (probablement derriere paywall)');
console.log('Telecharges sur disque  : ' + stats.downloaded);
console.log('Echecs download HTTP    : ' + stats.failed);
console.log('');
console.log('Pour augmenter le taux de recuperation :');
console.log('  - Configurez vos creds institutionnels dans Settings (a venir)');
console.log('  - Utilisez le module dedie de recherche API qui privilegie les articles OA');

try { await this.helpers.httpRequest({ method:'POST', url:'http://host.docker.internal:8080/api/module-progress/tick', body:JSON.stringify({current:toFetch.length, total:toFetch.length}), headers:{'Content-Type':'application/json'}, timeout:2000 }); } catch(e) {} /* PROGRESS_PDF_FINAL_v1 */
return allResults.map(r => ({ json: r }));
